1156	        constant mid_fmt_c  : FixFormat_t := cl_fix_add_fmt(a_fmt, b_fmt);
1157	        constant r_fmt_c    : FixFormat_t := choose(result_fmt = NullFixFormat_c, mid_fmt_c, result_fmt);
1158	        variable a_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1159	        variable b_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1160	        variable mid_v      : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
