1165	        -- However, a long-standing Vivado bug causes incorrect post-synthesis behavior in DSP
1166	        -- slices (pre-add or post-add) if numeric_std.unsigned is used. There are no known issues
1167	        -- for numeric_std.signed, so we always use that.
1168	        mid_v := std_logic_vector(signed(a_v) + signed(b_v));
1169	        return cl_fix_resize(mid_v, mid_fmt_c, r_fmt_c, round, saturate);
